diff --git a/llvm/lib/Analysis/ValueTracking.cpp b/llvm/lib/Analysis/ValueTracking.cpp
index 973943790c0a..760d757c2196 100644
--- a/llvm/lib/Analysis/ValueTracking.cpp
+++ b/llvm/lib/Analysis/ValueTracking.cpp
@@ -611,6 +611,7 @@ static bool isKnownNonZeroFromAssume(const Value *V, const SimplifyQuery &Q) {
            "must be an assume intrinsic");

     Value *RHS;
+    Value *X, *Y;
     CmpInst::Predicate Pred;
     auto m_V = m_CombineOr(m_Specific(V), m_PtrToInt(m_Specific(V)));
     if (!match(I->getArgOperand(0), m_c_ICmp(Pred, m_V, m_Value(RHS))))
@@ -2265,6 +2266,7 @@ static bool isKnownNonNullFromDominatingCondition(const Value *V,

     // Consider only compare instructions uniquely controlling a branch
     Value *RHS;
+    Value *X, *Y;
     CmpInst::Predicate Pred;
     if (!match(U, m_c_ICmp(Pred, m_Specific(V), m_Value(RHS))))
       continue;
@@ -2539,10 +2541,35 @@ static bool isKnownNonZeroFromOperator(const Operator *I,
   case Instruction::Sub:
     return isNonZeroSub(DemandedElts, Depth, Q, BitWidth, I->getOperand(0),
                         I->getOperand(1));
-  case Instruction::Or:
+  case Instruction::Or: {
     // X | Y != 0 if X != 0 or Y != 0.
-    return isKnownNonZero(I->getOperand(1), DemandedElts, Depth, Q) ||
-           isKnownNonZero(I->getOperand(0), DemandedElts, Depth, Q);
+    if (isKnownNonZero(I->getOperand(1), DemandedElts, Depth, Q) ||
+        isKnownNonZero(I->getOperand(0), DemandedElts, Depth, Q))
+      return true;
+
+    // (icmp ult (X + Y), X) | (icmp ult (X + Y), Y) is equivalent to carry-out
+    // of the addition, so either compare being true implies the other one.
+    // Recognize this to prove the OR is non-zero iff one side is non-zero.
+    Value *X, *Y;
+    CmpInst::Predicate Pred;
+    if ((match(I->getOperand(0),
+               m_ICmp(Pred, m_c_Add(m_Value(X), m_Value(Y)), m_Specific(X))) &&
+         Pred == CmpInst::ICMP_ULT &&
+         match(I->getOperand(1),
+               m_ICmp(Pred, m_c_Add(m_Specific(X), m_Specific(Y)),
+                      m_Specific(Y))) &&
+         Pred == CmpInst::ICMP_ULT) ||
+        (match(I->getOperand(1),
+               m_ICmp(Pred, m_c_Add(m_Value(X), m_Value(Y)), m_Specific(X))) &&
+         Pred == CmpInst::ICMP_ULT &&
+         match(I->getOperand(0),
+               m_ICmp(Pred, m_c_Add(m_Specific(X), m_Specific(Y)),
+                      m_Specific(Y))) &&
+         Pred == CmpInst::ICMP_ULT))
+      return true;
+
+    return false;
+  }
   case Instruction::SExt:
   case Instruction::ZExt:
     // ext X != 0 if X != 0.
@@ -4237,6 +4264,7 @@ static FPClassTest computeKnownFPClassFromAssumes(const Value *V,
     if (!isValidAssumeForContext(I, Q.CxtI, Q.DT))
       continue;

+    Value *X, *Y;
     CmpInst::Predicate Pred;
     Value *LHS, *RHS;
     uint64_t ClassVal = 0;
@@ -4403,6 +4431,7 @@ void computeKnownFPClass(const Value *V, const APInt &DemandedElts,
     FPClassTest TestedMask = fcNone;
     uint64_t ClassVal = 0;
     const Function *F = cast<Instruction>(Op)->getFunction();
+    Value *X, *Y;
     CmpInst::Predicate Pred;
     Value *CmpLHS, *CmpRHS;
     if (F && match(Cond, m_FCmp(Pred, m_Value(CmpLHS), m_Value(CmpRHS)))) {

